-- Lot 3 : les questions servies aux élèves viennent de la base de données.
-- 1) Lecture des questions pour les utilisateurs authentifiés et approuvés
--    (la policy « Admins can view questions » existante reste en place).

CREATE OR REPLACE FUNCTION public.is_approved_user(_user_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.profiles p
    WHERE p.id = _user_id AND p.is_approved
  );
$$;

DROP POLICY IF EXISTS "Approved users can view questions" ON public.questions;

CREATE POLICY "Approved users can view questions"
ON public.questions
FOR SELECT
TO authenticated
USING (public.is_approved_user(auth.uid()));

-- 2) Import initial des 452 questions du fichier statique.
--    Idempotent : ne touche pas aux questions déjà présentes en base
--    (les modifications faites via l'écran Administration sont préservées).

ON CONFLICT (id) DO NOTHING;
